/**
 * An abstract class for iterable Python nodes.
 *
 * @param <T> the type of Python object generated by this node
 */
public abstract class AIterablePyNode<T extends APyObj> extends APyNode<T> {

    /**
     * The left child node of this iterable node.
     */
    protected APyNode<?> leftChild;

    /**
     * The right child node of this iterable node.
     */
    protected APyNode<?> rightChild;

    /**
     * Returns the left child node of this node.
     *
     * @return the left child node of this node
     */
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child node of this node.
     *
     * @return the right child node of this node
     */
    public APyNode<?> getRightChild() {
        return this.rightChild;
    }
}

