package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A class representing a Python node for generating dictionary objects.
 *
 * @param <K> the type of key in the generated dictionaries
 * @param <V> the type of value in the generated dictionaries
 */
public class PyDictNode<K extends APyObj, V extends APyObj> extends AIterablePyNode<PyDictObj<K, V>> {

    /**
     * Constructor for a PyDictNode; initializes its key and value nodes to the inputs.
     *
     * @param keyNode the node representing the keys of this dictionary
     * @param valNode the node representing the values of this dictionary
     */
    public PyDictNode(APyNode<K> keyNode, APyNode<V> valNode) {
        this.leftChild = keyNode;
        this.rightChild = valNode;
    }

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     *
     * @return a set of all exhaustive values for this node
     */
    @Override
    public Set<PyDictObj<K, V>> genExVals() {
        Set<PyDictObj<K, V>> results = new HashSet<>();
        Set<K> keyOptions = (Set<K>) this.leftChild.genExVals();
        Set<V> valOptions = (Set<V>) this.rightChild.genExVals();
        List<K> keyOptionsList = new ArrayList<>(keyOptions);

        for (int length : this.exDomain) {
            Set<Set<K>> keySubsets = this.generateAllKeySubsets(length, keyOptionsList);
            for (Set<K> keys : keySubsets) {
                Set<Map<K, V>> mappings = this.generateAllMappings(new ArrayList<>(keys), valOptions);
                for (Map<K, V> map : mappings) {
                    results.add(new PyDictObj<>(map));
                }
            }
        }
        return results;
    }

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    @Override
    public PyDictObj<K, V> genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        Random rand = new Random();
        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        Map<K, V> map = new HashMap<>();
        int attempts = 0;
        while (map.size() < length && attempts < 1000) {
            K key = (K) this.leftChild.genRandVal();
            V val = (V) this.rightChild.genRandVal();
            map.put(key, val);
            attempts++;
        }

        return new PyDictObj<>(map);
    }

    /**
     * Helper method to generate all possible subsets of keys of a certain size.
     *
     * @param size the size of the subsets to generate
     * @param options the possible keys
     * @return a set of all possible subsets of keys of the given size
     */
    private Set<Set<K>> generateAllKeySubsets(int size, List<K> options) {
        Set<Set<K>> results = new HashSet<>();
        if (size == 0) {
            results.add(new HashSet<>());
            return results;
        }
        if (options.size() < size) {
            return results;
        }
        generateKeyCombinations(0, size, options, new HashSet<>(), results);
        return results;
    }

    private void generateKeyCombinations(int start, int size, List<K> options, Set<K> current, Set<Set<K>> results) {
        if (current.size() == size) {
            results.add(new HashSet<>(current));
            return;
        }
        for (int i = start; i < options.size(); i++) {
            current.add(options.get(i));
            generateKeyCombinations(i + 1, size, options, current, results);
            current.remove(options.get(i));
        }
    }

    /**
     * Helper method to generate all possible mappings from a fixed set of keys to any of the value options.
     *
     * @param keys the set of keys to map
     * @param valOptions the possible values for each key
     * @return a set of all possible mappings
     */
    private Set<Map<K, V>> generateAllMappings(List<K> keys, Set<V> valOptions) {
        Set<Map<K, V>> results = new HashSet<>();
        if (keys.isEmpty()) {
            results.add(new HashMap<>());
            return results;
        }
        if (valOptions.isEmpty()) {
            return results;
        }

        K firstKey = keys.get(0);
        List<K> remainingKeys = keys.subList(1, keys.size());
        Set<Map<K, V>> subMappings = generateAllMappings(remainingKeys, valOptions);

        for (Map<K, V> subMap : subMappings) {
            for (V val : valOptions) {
                Map<K, V> newMap = new HashMap<>(subMap);
                newMap.put(firstKey, val);
                results.add(newMap);
            }
        }
        return results;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * A class representing a Python node for generating integer objects.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     * For PyIntNode, the domain specification is a list of integers to be generated.
     *
     * @return a set of all exhaustive values for this node
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> results = new HashSet<>();
        for (Integer val : this.exDomain) {
            results.add(new PyIntObj(val));
        }
        return results;
    }

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    @Override
    public PyIntObj genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        int randomIndex = new Random().nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(randomIndex));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;
import java.util.*;

/**
 * A class representing a Python node for generating set objects.
 *
 * @param <E> the type of element in the generated sets
 */
public class PySetNode<E extends APyObj> extends AIterablePyNode<PySetObj<E>> {

    /**
     * Constructor for a PySetNode; initializes its child node to the input.
     *
     * @param child the node representing the elements of this set
     */
    public PySetNode(APyNode<E> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     *
     * @return a set of all exhaustive values for this node
     */
    @Override
    public Set<PySetObj<E>> genExVals() {
        Set<PySetObj<E>> results = new HashSet<>();
        Set<E> elementOptions = (Set<E>) this.leftChild.genExVals();
        List<E> optionsList = new ArrayList<>(elementOptions);

        for (int length : this.exDomain) {
            Set<Set<E>> combinations = this.generateAllSubsets(length, optionsList);
            for (Set<E> combo : combinations) {
                results.add(new PySetObj<>(combo));
            }
        }
        return results;
    }

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    @Override
    public PySetObj<E> genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        Random rand = new Random();
        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        Set<E> elements = new HashSet<>();
        // Note: For sets, we need to generate UNIQUE elements.
        // If we can't generate enough unique elements, what do we do?
        // Usually, in these assignments, we can assume the random domain 
        // will allow for it, or we try until we have enough.
        // However, if the total possible values is less than length, 
        // this might loop forever.
        // For now, let's just generate until we have enough.

        // Actually, we should probably pick from the child's random domain
        // or just call genRandVal() until we have enough unique ones.
        // But some nodes (like PyIntNode) might have a small random domain.

        // Let's try to be a bit safer.
        int attempts = 0;
        while (elements.size() < length && attempts < 1000) {
            elements.add((E) this.leftChild.genRandVal());
            attempts++;
        }

        return new PySetObj<>(elements);
    }

    /**
     * Helper method to generate all possible subsets of a certain size.
     *
     * @param size the size of the subsets to generate
     * @param options the possible elements for the subsets
     * @return a set of all possible subsets of the given size
     */
    private Set<Set<E>> generateAllSubsets(int size, List<E> options) {
        Set<Set<E>> results = new HashSet<>();
        if (size == 0) {
            results.add(new HashSet<>());
            return results;
        }
        if (options.size() < size) {
            return results;
        }

        // Combinations using recursion
        generateCombinations(0, size, options, new HashSet<>(), results);
        return results;
    }

    private void generateCombinations(int start, int size, List<E> options, Set<E> current, Set<Set<E>> results) {
        if (current.size() == size) {
            results.add(new HashSet<>(current));
            return;
        }
        for (int i = start; i < options.size(); i++) {
            current.add(options.get(i));
            generateCombinations(i + 1, size, options, current, results);
            current.remove(options.get(i));
        }
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a Python node used to generate objects of a certain type.
 * Each node represents a domain of possible values and can generate exhaustive or random values.
 *
 * @param <T> the type of Python object generated by this node
 */
public abstract class APyNode<T extends APyObj> {

    /**
     * The exhaustive domain specification for this node.
     */
    protected List<Integer> exDomain;

    /**
     * The random domain specification for this node.
     */
    protected List<Integer> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain for this node
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain to set
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain for this node
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain to set
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     *
     * @return a set of all exhaustive values for this node
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    public abstract T genRandVal();
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A class for generating base test cases from a list of PyNodes.
 */
public class BaseSetGenerator {

    /**
     * The list of nodes to generate test cases from.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random test cases to generate.
     */
    private final int numRand;

    /**
     * Constructor for a BaseSetGenerator; initializes its nodes and numRand to the inputs.
     *
     * @param nodes the list of nodes to generate test cases from
     * @param numRand the number of random test cases to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all possible exhaustive test cases by taking the Cartesian product
     * of the exhaustive values generated by each node.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        List<Set<? extends APyObj>> nodeVals = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            nodeVals.add(node.genExVals());
        }

        Set<List<APyObj>> cartesianProduct = generateCartesianProduct(nodeVals);
        Set<TestCase> results = new HashSet<>();
        for (List<APyObj> args : cartesianProduct) {
            results.add(new TestCase(args));
        }
        return results;
    }

    /**
     * Generates the specified number of random test cases.
     *
     * @param numTests the number of random test cases to generate
     * @return a list of random test cases
     */
    public List<TestCase> genRandTests(int numTests) {
        List<TestCase> results = new ArrayList<>();
        for (int i = 0; i < numTests; i++) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : this.nodes) {
                args.add(node.genRandVal());
            }
            results.add(new TestCase(args));
        }
        return results;
    }

    /**
     * Generates a combined list of test cases including all exhaustive ones and
     * then adding the specified number of random ones (avoiding duplicates from
     * the exhaustive ones).
     *
     * @return a list of all test cases
     */
    public List<TestCase> genBaseSet() {
        return this.genTests(this.numRand);
    }

    /**
     * Generates a combined list of test cases including all exhaustive ones and
     * then adding the specified number of random ones (avoiding duplicates from
     * the exhaustive ones).
     *
     * @param numRand the number of random test cases to generate
     * @return a list of all test cases
     */
    public List<TestCase> genTests(int numRand) {
        Set<TestCase> exTests = this.genExTests();
        List<TestCase> baseSet = new ArrayList<>(exTests);
        Set<TestCase> allTests = new HashSet<>(exTests);

        int attempts = 0;
        int added = 0;
        while (added < numRand && attempts < 1000) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : this.nodes) {
                args.add(node.genRandVal());
            }
            TestCase randomCase = new TestCase(args);
            if (!allTests.contains(randomCase)) {
                baseSet.add(randomCase);
                allTests.add(randomCase);
                added++;
            }
            attempts++;
        }

        return baseSet;
    }

    /**
     * Helper method to generate the Cartesian product of sets of values.
     *
     * @param nodeVals the sets of values to take the product of
     * @return a set of all combinations of values
     */
    private Set<List<APyObj>> generateCartesianProduct(List<Set<? extends APyObj>> nodeVals) {
        Set<List<APyObj>> results = new HashSet<>();
        if (nodeVals.isEmpty()) {
            results.add(new ArrayList<>());
            return results;
        }

        Set<? extends APyObj> firstSet = nodeVals.get(0);
        List<Set<? extends APyObj>> remainingSets = nodeVals.subList(1, nodeVals.size());
        Set<List<APyObj>> subProduct = generateCartesianProduct(remainingSets);

        for (APyObj val : firstSet) {
