+
+/**
+ * A class for generating base test cases from a list of PyNodes.
+ */
+public class BaseSetGenerator {
+
+    /**
+     * The list of nodes to generate test cases from.
+     */
+    private final List<APyNode<?>> nodes;
+
+    /**
+     * The number of random test cases to generate.
+     */
+    private final int numRand;
+
+    /**
+     * Constructor for a BaseSetGenerator; initializes its nodes and numRand to the inputs.
+     *
+     * @param nodes the list of nodes to generate test cases from
+     * @param numRand the number of random test cases to generate
+     */
+    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
+        this.nodes = nodes;
+        this.numRand = numRand;
+    }
+
+    /**
+     * Generates all possible exhaustive test cases by taking the Cartesian product
+     * of the exhaustive values generated by each node.
+     *
+     * @return a set of all exhaustive test cases
+     */
+    public Set<TestCase> genExTests() {
+        List<Set<? extends APyObj>> nodeVals = new ArrayList<>();
+        for (APyNode<?> node : this.nodes) {
+            nodeVals.add(node.genExVals());
+        }
+        
+        Set<List<APyObj>> cartesianProduct = generateCartesianProduct(nodeVals);
+        Set<TestCase> results = new HashSet<>();
+        for (List<APyObj> args : cartesianProduct) {
+            results.add(new TestCase(args));
+        }
+        return results;
+    }
+
+    /**
+     * Generates the specified number of random test cases.
+     *
+     * @param numTests the number of random test cases to generate
+     * @return a list of random test cases
+     */
+    public List<TestCase> genRandTests(int numTests) {
+        List<TestCase> results = new ArrayList<>();
+        for (int i = 0; i < numTests; i++) {
+            List<APyObj> args = new ArrayList<>();
+            for (APyNode<?> node : this.nodes) {
+                args.add(node.genRandVal());
+            }
+            results.add(new TestCase(args));
+        }
+        return results;
+    }
+
+    /**
+     * Generates a combined list of test cases including all exhaustive ones and
+     * then adding the specified number of random ones (avoiding duplicates from
+     * the exhaustive ones).
+     *
+     * @return a list of all test cases
+     */
+    public List<TestCase> genBaseSet() {
+        return this.genTests(this.numRand);
+    }
+
+    /**
+     * Generates a combined list of test cases including all exhaustive ones and
+     * then adding the specified number of random ones (avoiding duplicates from
+     * the exhaustive ones).
+     *
+     * @param numRand the number of random test cases to generate
+     * @return a list of all test cases
+     */
+    public List<TestCase> genTests(int numRand) {
+        Set<TestCase> exTests = this.genExTests();
+        List<TestCase> baseSet = new ArrayList<>(exTests);
+        Set<TestCase> allTests = new HashSet<>(exTests);
+
+        int attempts = 0;
+        int added = 0;
+        while (added < numRand && attempts < 1000) {
+            List<APyObj> args = new ArrayList<>();
+            for (APyNode<?> node : this.nodes) {
+                args.add(node.genRandVal());
+            }
+            TestCase randomCase = new TestCase(args);
+            if (!allTests.contains(randomCase)) {
+                baseSet.add(randomCase);
+                allTests.add(randomCase);
+                added++;
+            }
+            attempts++;
+        }
+
+        return baseSet;
+    }
+
+    /**
+     * Helper method to generate the Cartesian product of sets of values.
+     *
+     * @param nodeVals the sets of values to take the product of
+     * @return a set of all combinations of values
+     */
+    private Set<List<APyObj>> generateCartesianProduct(List<Set<? extends APyObj>> nodeVals) {
+        Set<List<APyObj>> results = new HashSet<>();
+        if (nodeVals.isEmpty()) {
+            results.add(new ArrayList<>());
+            return results;
+        }
+
+        Set<? extends APyObj> firstSet = nodeVals.get(0);
+        List<Set<? extends APyObj>> remainingSets = nodeVals.subList(1, nodeVals.size());
+        Set<List<APyObj>> subProduct = generateCartesianProduct(remainingSets);
+
+        for (APyObj val : firstSet) {
+            for (List<APyObj> subCombination : subProduct) {
+                List<APyObj> combination = new ArrayList<>();
+                combination.add(val);
+                combination.addAll(subCombination);
+                results.add(combination);
+            }
+        }
+        return results;
+    }
+}
