+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import main.rice.obj.PyDictObj;
+import java.util.*;
+
+/**
+ * A class representing a Python node for generating dictionary objects.
+ *
+ * @param <K> the type of key in the generated dictionaries
+ * @param <V> the type of value in the generated dictionaries
+ */
+public class PyDictNode<K extends APyObj, V extends APyObj> extends AIterablePyNode<PyDictObj<K, V>> {
+
+    /**
+     * Constructor for a PyDictNode; initializes its key and value nodes to the inputs.
+     *
+     * @param keyNode the node representing the keys of this dictionary
+     * @param valNode the node representing the values of this dictionary
+     */
+    public PyDictNode(APyNode<K> keyNode, APyNode<V> valNode) {
+        this.leftChild = keyNode;
+        this.rightChild = valNode;
+    }
+
+    /**
+     * Generates all exhaustive values for this node based on its exhaustive domain.
+     *
+     * @return a set of all exhaustive values for this node
+     */
+    @Override
+    public Set<PyDictObj<K, V>> genExVals() {
+        Set<PyDictObj<K, V>> results = new HashSet<>();
+        Set<K> keyOptions = (Set<K>) this.leftChild.genExVals();
+        Set<V> valOptions = (Set<V>) this.rightChild.genExVals();
+        List<K> keyOptionsList = new ArrayList<>(keyOptions);
+
+        for (int length : this.exDomain) {
+            Set<Set<K>> keySubsets = this.generateAllKeySubsets(length, keyOptionsList);
+            for (Set<K> keys : keySubsets) {
+                Set<Map<K, V>> mappings = this.generateAllMappings(new ArrayList<>(keys), valOptions);
+                for (Map<K, V> map : mappings) {
+                    results.add(new PyDictObj<>(map));
+                }
+            }
+        }
+        return results;
+    }
+
+    /**
+     * Generates a single random value for this node based on its random domain.
+     *
+     * @return a single random value for this node
+     */
+    @Override
+    public PyDictObj<K, V> genRandVal() {
+        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
+            return null;
+        }
+        Random rand = new Random();
+        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
+        
+        Map<K, V> map = new HashMap<>();
+        int attempts = 0;
+        while (map.size() < length && attempts < 1000) {
+            K key = (K) this.leftChild.genRandVal();
+            V val = (V) this.rightChild.genRandVal();
+            map.put(key, val);
+            attempts++;
+        }
+        
+        return new PyDictObj<>(map);
+    }
+
+    /**
+     * Helper method to generate all possible subsets of keys of a certain size.
+     *
+     * @param size the size of the subsets to generate
+     * @param options the possible keys
+     * @return a set of all possible subsets of keys of the given size
+     */
+    private Set<Set<K>> generateAllKeySubsets(int size, List<K> options) {
+        Set<Set<K>> results = new HashSet<>();
+        if (size == 0) {
+            results.add(new HashSet<>());
+            return results;
+        }
+        if (options.size() < size) {
+            return results;
+        }
+        generateKeyCombinations(0, size, options, new HashSet<>(), results);
+        return results;
+    }
+
+    private void generateKeyCombinations(int start, int size, List<K> options, Set<K> current, Set<Set<K>> results) {
+        if (current.size() == size) {
+            results.add(new HashSet<>(current));
+            return;
+        }
+        for (int i = start; i < options.size(); i++) {
+            current.add(options.get(i));
+            generateKeyCombinations(i + 1, size, options, current, results);
+            current.remove(options.get(i));
+        }
+    }
+
+    /**
+     * Helper method to generate all possible mappings from a fixed set of keys to any of the value options.
+     *
+     * @param keys the set of keys to map
+     * @param valOptions the possible values for each key
+     * @return a set of all possible mappings
+     */
+    private Set<Map<K, V>> generateAllMappings(List<K> keys, Set<V> valOptions) {
+        Set<Map<K, V>> results = new HashSet<>();
+        if (keys.isEmpty()) {
+            results.add(new HashMap<>());
+            return results;
+        }
+        if (valOptions.isEmpty()) {
+            return results;
+        }
+
+        K firstKey = keys.get(0);
+        List<K> remainingKeys = keys.subList(1, keys.size());
+        Set<Map<K, V>> subMappings = generateAllMappings(remainingKeys, valOptions);
+
+        for (Map<K, V> subMap : subMappings) {
+            for (V val : valOptions) {
+                Map<K, V> newMap = new HashMap<>(subMap);
+                newMap.put(firstKey, val);
+                results.add(newMap);
+            }
+        }
+        return results;
+    }
+}
