+public class PySetNode<E extends APyObj> extends AIterablePyNode<PySetObj<E>> {
+
+    /**
+     * Constructor for a PySetNode; initializes its child node to the input.
+     *
+     * @param child the node representing the elements of this set
+     */
+    public PySetNode(APyNode<E> child) {
+        this.leftChild = child;
+    }
+
+    /**
+     * Generates all exhaustive values for this node based on its exhaustive domain.
+     *
+     * @return a set of all exhaustive values for this node
+     */
+    @Override
+    public Set<PySetObj<E>> genExVals() {
+        Set<PySetObj<E>> results = new HashSet<>();
+        Set<E> elementOptions = (Set<E>) this.leftChild.genExVals();
+        List<E> optionsList = new ArrayList<>(elementOptions);
+
+        for (int length : this.exDomain) {
+            Set<Set<E>> combinations = this.generateAllSubsets(length, optionsList);
+            for (Set<E> combo : combinations) {
+                results.add(new PySetObj<>(combo));
+            }
+        }
+        return results;
+    }
+
+    /**
+     * Generates a single random value for this node based on its random domain.
+     *
+     * @return a single random value for this node
+     */
+    @Override
+    public PySetObj<E> genRandVal() {
+        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
+            return null;
+        }
+        Random rand = new Random();
+        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
+        
+        Set<E> elements = new HashSet<>();
+        // Note: For sets, we need to generate UNIQUE elements.
+        // If we can't generate enough unique elements, what do we do?
+        // Usually, in these assignments, we can assume the random domain 
+        // will allow for it, or we try until we have enough.
+        // However, if the total possible values is less than length, 
+        // this might loop forever.
+        // For now, let's just generate until we have enough.
+        
+        // Actually, we should probably pick from the child's random domain
+        // or just call genRandVal() until we have enough unique ones.
+        // But some nodes (like PyIntNode) might have a small random domain.
+        
+        // Let's try to be a bit safer.
+        int attempts = 0;
+        while (elements.size() < length && attempts < 1000) {
+            elements.add((E) this.leftChild.genRandVal());
+            attempts++;
+        }
+        
+        return new PySetObj<>(elements);
+    }
+
+    /**
+     * Helper method to generate all possible subsets of a certain size.
+     *
+     * @param size the size of the subsets to generate
+     * @param options the possible elements for the subsets
+     * @return a set of all possible subsets of the given size
+     */
