+        Set<Set<E>> results = new HashSet<>();
+        if (size == 0) {
+            results.add(new HashSet<>());
+            return results;
+        }
+        if (options.size() < size) {
+            return results;
+        }
+
+        // Combinations using recursion
+        generateCombinations(0, size, options, new HashSet<>(), results);
+        return results;
+    }
+
+    private void generateCombinations(int start, int size, List<E> options, Set<E> current, Set<Set<E>> results) {
+        if (current.size() == size) {
+            results.add(new HashSet<>(current));
+            return;
+        }
+        for (int i = start; i < options.size(); i++) {
