+import java.util.*;
+
+/**
+ * A class representing a Python node for generating tuple objects.
+ *
+ * @param <E> the type of element in the generated tuples
+ */
+public class PyTupleNode<E extends APyObj> extends AIterablePyNode<PyTupleObj<E>> {
+
+    /**
+     * Constructor for a PyTupleNode; initializes its child node to the input.
+     *
+     * @param child the node representing the elements of this tuple
+     */
+    public PyTupleNode(APyNode<E> child) {
+        this.leftChild = child;
+    }
+
+    /**
+     * Generates all exhaustive values for this node based on its exhaustive domain.
+     *
+     * @return a set of all exhaustive values for this node
+     */
+    @Override
+    public Set<PyTupleObj<E>> genExVals() {
+        Set<PyTupleObj<E>> results = new HashSet<>();
+        Set<E> elementOptions = (Set<E>) this.leftChild.genExVals();
+
+        for (int length : this.exDomain) {
+            Set<List<E>> combinations = this.generateAllLists(length, elementOptions);
+            for (List<E> combo : combinations) {
+                results.add(new PyTupleObj<>(combo));
+            }
+        }
+        return results;
+    }
+
+    /**
+     * Generates a single random value for this node based on its random domain.
+     *
+     * @return a single random value for this node
+     */
+    @Override
+    public PyTupleObj<E> genRandVal() {
+        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
+            return null;
+        }
+        Random rand = new Random();
+        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));
+        List<E> elements = new ArrayList<>();
+        for (int i = 0; i < length; i++) {
+            elements.add((E) this.leftChild.genRandVal());
+        }
+        return new PyTupleObj<>(elements);
+    }
+
+    /**
+     * Helper method to generate all possible lists of a certain length.
+     *
+     * @param length the length of the lists to generate
+     * @param options the possible elements for the lists
+     * @return a set of all possible lists of the given length
+     */
+    private Set<List<E>> generateAllLists(int length, Set<E> options) {
+        Set<List<E>> results = new HashSet<>();
+        if (length == 0) {
+            results.add(new ArrayList<>());
+            return results;
+        }
+        if (options.isEmpty()) {
+            return results;
+        }
+
+        Set<List<E>> subLists = generateAllLists(length - 1, options);
+        for (List<E> subList : subLists) {
+            for (E option : options) {
+                List<E> newList = new ArrayList<>(subList);
+                newList.add(option);
+                results.add(newList);
+            }
+        }
+        return results;
+    }
+}
